const task = $input.first().json;

// Helper: get custom field value by name
function getField(name) {
  const fields = task.custom_fields || [];
  const f = fields.find(f => f.name.toLowerCase() === name.toLowerCase());
  if (!f) return '';
  return f.value || '';
}

// Accounts: comma-separated string → array
const accountsRaw = getField('Accounts');
const accounts = accountsRaw
  ? accountsRaw.split(',').map(a => a.trim()).filter(Boolean)
  : [];

return [{
  json: {
    source:     'clickup',
    source_id:  task.id,
    task_name:  task.name,
    accounts:   accounts,
    reel_url:   getField('Reel URL'),
    cover_url:  getField('Cover URL'),
    caption:    getField('Caption'),
    title:      getField('Title') || task.name
  }
}];

const row = $json;

// row_number is auto-added by n8n Sheets node as the actual row index
const rowId = String($itemIndex + 2); // +2 because row 1 = header

// Accounts: comma-separated → array
const accountsRaw = row['Accounts'] || '';
const accounts = accountsRaw
  .split(',')
  .map(a => a.trim())
  .filter(Boolean);

return {
  json: {
    source:     'sheet',
    source_id:  rowId,
    task_name:  row['Title'] || 'Row ' + rowId,
    accounts:   accounts,
    reel_url:   row['Reel URL'] || '',
    cover_url:  row['Cover URL'] || '',
    caption:    row['Caption'] || '',
    title:      row['Title'] || 'Video'
  }
};

const results = $input.all();
const summary = results.map(r => {
  const d = r.json;
  return `✅ ${d.platform} | ${d.account} | post: ${d.post_id} | at: ${d.posted_at}`;
}).join('\n');

console.log('Upload batch complete:\n' + summary);
return results;

// Edit this to test different scenarios
return [{
  json: {
    source:     'clickup',
    source_id:  'task_test_001',
    accounts:   ['arya instagram', 'arya youtube', 'arya linkedin'],
    reel_url:   'https://drive.google.com/file/d/YOUR_REEL_FILE_ID/view?usp=sharing',
    cover_url:  'https://drive.google.com/file/d/YOUR_COVER_FILE_ID/view?usp=sharing',
    caption:    'Test caption from main workflow! #test #reels',
    title:      'Test Upload Video'
  }
}];

const norm = $('Loop Over Items').first().json;
const coverFile = $input.first().json;

const reelurl = $('final video id').first().json;
// Build direct download URL from the Drive file ID
const coverUrl = coverFile.id
  ? `https://drive.google.com/uc?export=download&id=${coverFile.id}`
  : '';

const reelUrl = coverFile.id
  ? `https://drive.google.com/uc?export=download&id=${reelurl.id}`
  : '';



return [{
  json: {
    ...norm,
    reel_url:reelUrl,
    cover_url: coverUrl,
    cover_file_id: coverFile.id || ''
  }
}];

